+    fallback: ((value: input) => unknown) | undefined,
+    throwOnEmpty: boolean
+  ): unknown[] {
+    if (!this.hasInput) return this.evaluate(undefined as input, fallback, throwOnEmpty) as unknown[];
+    return this.evaluate(this.input as input, fallback, throwOnEmpty) as unknown[];
+  }
